import { MARKER_HALF_WIDTH } from '../renderers/value-marker-renderer/constants.js';

export function getDefaultValueMarkerPointerPosition(
  originalXPosition: number,
  trackLeftBoundary: number,
  trackRightBoundary: number,
) {
  if (originalXPosition - MARKER_HALF_WIDTH <= trackLeftBoundary) {
    return 'left';
  }
  if (originalXPosition + MARKER_HALF_WIDTH > trackRightBoundary) {
    return 'right';
  }
  return 'center';
}
